        \item \textbf{【详解】} $\because$点$P(2,5)$在角$\alpha$终边上, $\therefore \sin \alpha = \frac{5\sqrt{29}}{29}$, $\cos \alpha = \frac{2\sqrt{29}}{29}$, $\therefore \frac{2\cos(\pi + \alpha) - 3\sin(\pi - \alpha)}{4\cos(-\alpha) + \sin(2\pi + \alpha)} = \frac{-2\cos \alpha - 3\sin \alpha}{4\cos \alpha + \sin \alpha} = -\frac{19}{13}$。
    \end{itemize}
\end{enumerate}
